// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb.benchmark;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.Properties;
import java.util.concurrent.atomic.AtomicInteger;

import org.eclipse.rdf4j.sail.lmdb.benchmark.BenchmarkJoinEstimatorSupport.ThemeRegressionStore;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class BenchmarkJoinEstimatorSupportPersistentStoreTest {

	@AfterEach
	void clearSystemProperties() {
		System.clearProperty(BenchmarkJoinEstimatorSupport.persistentThemeRegressionStoreEnabledPropertyName());
		System.clearProperty(BenchmarkJoinEstimatorSupport.persistentThemeRegressionStoreRootPropertyName());
	}

	@Test
	void prepareThemeRegressionStoreUsesTemporaryDirectoryWhenPersistentModeIsDisabled(@TempDir Path dataDir)
			throws Exception {
		AtomicInteger buildCount = new AtomicInteger();
		Path temporaryStore = dataDir.resolve("temporary-store");

		ThemeRegressionStore preparedStore = BenchmarkJoinEstimatorSupport.prepareThemeRegressionStore(
				temporaryStore,
				"disabled/social",
				storeDirectory -> {
					buildCount.incrementAndGet();
					writeFakeStoreDataFiles(storeDirectory, 17, 19);
				});

		assertFalse(preparedStore.persistent());
		assertFalse(preparedStore.reused());
		assertEquals(temporaryStore.toAbsolutePath().normalize(), preparedStore.storeDirectory());
		assertEquals(1, buildCount.get());

		BenchmarkJoinEstimatorSupport.cleanupThemeRegressionStore(preparedStore);
		assertFalse(Files.exists(preparedStore.storeDirectory()));
	}

	@Test
	void prepareThemeRegressionStoreReusesPersistentStoreWhenSizesMatch(@TempDir Path dataDir) throws Exception {
		System.setProperty(BenchmarkJoinEstimatorSupport.persistentThemeRegressionStoreEnabledPropertyName(), "true");
		System.setProperty(BenchmarkJoinEstimatorSupport.persistentThemeRegressionStoreRootPropertyName(),
				dataDir.resolve("persistent-lmdb-theme-store").toString());

		AtomicInteger buildCount = new AtomicInteger();
		ThemeRegressionStore first = BenchmarkJoinEstimatorSupport.prepareThemeRegressionStore(
				dataDir.resolve("ignored"),
				"theme-query-regression/social-media",
				storeDirectory -> {
					buildCount.incrementAndGet();
					writeFakeStoreDataFiles(storeDirectory, 23, 29);
				});
		ThemeRegressionStore second = BenchmarkJoinEstimatorSupport.prepareThemeRegressionStore(
				dataDir.resolve("ignored"),
				"theme-query-regression/social-media",
				storeDirectory -> {
					buildCount.incrementAndGet();
					writeFakeStoreDataFiles(storeDirectory, 31, 37);
				});

		assertTrue(first.persistent());
		assertFalse(first.reused());
		assertTrue(second.persistent());
		assertTrue(second.reused());
		assertEquals(first.storeDirectory(), second.storeDirectory());
		assertEquals(1, buildCount.get());

		BenchmarkJoinEstimatorSupport.cleanupThemeRegressionStore(second);
		assertTrue(Files.exists(second.storeDirectory()));
	}

	@Test
	void prepareThemeRegressionStoreRebuildsPersistentStoreWhenSizesMismatch(@TempDir Path dataDir) throws Exception {
		System.setProperty(BenchmarkJoinEstimatorSupport.persistentThemeRegressionStoreEnabledPropertyName(), "true");
		System.setProperty(BenchmarkJoinEstimatorSupport.persistentThemeRegressionStoreRootPropertyName(),
				dataDir.resolve("persistent-lmdb-theme-store").toString());

		AtomicInteger buildCount = new AtomicInteger();
		ThemeRegressionStore first = BenchmarkJoinEstimatorSupport.prepareThemeRegressionStore(
				dataDir.resolve("ignored"),
				"theme-query-regression/pharma",
				storeDirectory -> {
					buildCount.incrementAndGet();
					writeFakeStoreDataFiles(storeDirectory, 41, 43);
				});
		writeIncorrectExpectedSizes(first.storeDirectory(), 1, 1);

		ThemeRegressionStore second = BenchmarkJoinEstimatorSupport.prepareThemeRegressionStore(
				dataDir.resolve("ignored"),
				"theme-query-regression/pharma",
				storeDirectory -> {
					buildCount.incrementAndGet();
					writeFakeStoreDataFiles(storeDirectory, 47, 53);
				});

		assertTrue(second.persistent());
		assertFalse(second.reused());
		assertEquals(2, buildCount.get());
		assertEquals(47L, Files.size(second.storeDirectory().resolve("triples/data.mdb")));
		assertEquals(53L, Files.size(second.storeDirectory().resolve("values/data.mdb")));
	}

	private static void writeFakeStoreDataFiles(Path storeDirectory, int triplesSizeBytes, int valuesSizeBytes)
			throws IOException {
		Files.createDirectories(storeDirectory.resolve("triples"));
		Files.createDirectories(storeDirectory.resolve("values"));
		Files.write(storeDirectory.resolve("triples/data.mdb"), new byte[triplesSizeBytes]);
		Files.write(storeDirectory.resolve("values/data.mdb"), new byte[valuesSizeBytes]);
	}

	private static void writeIncorrectExpectedSizes(Path storeDirectory, long triplesSizeBytes, long valuesSizeBytes)
			throws IOException {
		Properties properties = new Properties();
		properties.setProperty("triples.data.mdb.size.bytes", Long.toString(triplesSizeBytes));
		properties.setProperty("values.data.mdb.size.bytes", Long.toString(valuesSizeBytes));
		try (var outputStream = Files.newOutputStream(storeDirectory.resolve("expected-db-file-sizes.properties"))) {
			properties.store(outputStream, "incorrect sizes for mismatch testing");
		}
	}
}
